import React, { useEffect, useState } from 'react';

import { api } from '../api/api';

interface ServicesPageProps {
    onRequest?: () => void;
}

interface Service {
    id: number;
    title: string;
    description: string;
    icon: string;
    price: string;
}

const ServicesPage: React.FC<ServicesPageProps> = ({ onRequest }) => {
    const [services, setServices] = useState<Service[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        api.getServices()
            .then(data => {
                setServices(data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setError('Не удалось загрузить услуги');
                setLoading(false);
            });
    }, []);

    if (loading) return <div className="page-shell text-center font-semibold text-graphite-500">Загрузка услуг...</div>;

    if (error) return <div className="page-shell text-center font-semibold text-red-600">{error}</div>;

    return (
        <div className="page-shell">
            <div className="mb-10">
                <h1 className="page-title">Наши услуги</h1>
            </div>

            <div className="grid grid-cols-1 gap-6 md:grid-cols-3">
                {services.map(service => (
                    <div key={service.id} className="card-hover relative overflow-hidden p-6">
                        <div className="absolute right-0 top-0 h-28 w-28 rounded-bl-[4rem] bg-factory-50" />
                        <div className="relative">
                            <div className="mb-5 flex h-16 w-16 items-center justify-center rounded-2xl bg-graphite-950 text-3xl shadow-card">
                                {service.icon || ''}
                            </div>
                            <h3 className="font-display text-2xl font-black text-graphite-950">{service.title}</h3>
                            <p className="mt-3 min-h-[5rem] text-sm leading-6 text-graphite-600">{service.description}</p>

                            <div className="mt-6 rounded-2xl border border-graphite-100 bg-graphite-50/80 p-4">
                                <span className="text-xs font-bold uppercase tracking-[0.18em] text-graphite-400">Стоимость</span>
                                <p className="mt-1 text-xl font-black text-factory-700">{service.price}</p>
                            </div>

                        </div>
                    </div>
                ))}
            </div>

            {onRequest && (
                <div className="mt-10 text-center">
                    <button type="button" onClick={onRequest} className="btn-primary px-8">
                        Получить консультацию
                    </button>
                </div>
            )}
        </div>
    );
};

export default ServicesPage;
